import { Component, OnInit } from '@angular/core';
import { ChessService } from '../../services/chess.service'; // Ajuste le chemin selon ton architecture

@Component({
  selector: 'app-chess-dashboard',
  templateUrl: './chess-dashboard.component.html',
  styleUrls: ['./chess-dashboard.component.css']
})
export class ChessDashboardComponent implements OnInit {
  // Position initiale par défaut
  currentFen: string = 'rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1';
  aiAnalysis: string = "Déplacez une pièce pour demander l'analyse de l'agent IA FFE.";

  // ⏳ Indicateurs de contrôle d'état pour l'UI
  isLoading: boolean = false;
  errorMessage: string | null = null;

  constructor(private chessService: ChessService) {}

  ngOnInit(): void {}

  /**
   * Méthode déclenchée à chaque coup joué sur l'échiquier ngx-chessboard
   */
  onBoardMove(newFen: string) {
    this.currentFen = newFen;
    this.isLoading = true;       // Active le spinner de chargement immédiatement
    this.errorMessage = null;    // Efface une éventuelle erreur précédente

    this.chessService.analyzePosition(newFen).subscribe({
      next: (data) => {
        if (data && data.status === 'success') {
          this.aiAnalysis = data.response;
        } else {
          // Cas où l'API répond 200 mais avec un statut d'échec interne
          this.aiAnalysis = "Impossible de récupérer l'analyse.";
        }
        this.isLoading = false;  // Désactive le spinner
      },
      error: (err) => {
        console.error('Erreur retournée par le backend FastAPI :', err);
        // Gestion de l'affichage de l'erreur réseau ou timeout
        this.errorMessage = "⚠️ Le service d'analyse de la FFE est temporairement indisponible (ou timeout dépassé). Veuillez rejouer votre coup.";
        this.isLoading = false;  // Désactive le spinner pour libérer l'écran
      }
    });
  }
}/**
   * Méthode pour réinitialiser l'état du dashboard
   */
  resetDashboard() {
    this.currentFen = 'rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1';
    this.aiAnalysis = "Déplacez une pièce pour demander l'analyse de l'agent IA FFE.";
    this.errorMessage = null;
    this.isLoading = false;
  }
